import Foundation

public class Message2Resolver {

    public init() {}

    private var resolvedToolIndex: [String: String] = [:]
    private var resolvedRequestIndex: [String: String] = [:]

    public func reset() {
        resolvedToolIndex = [:]
        resolvedRequestIndex = [:]
    }

    public func resolve(_ json: Any) throws -> Message2 {
        guard let dict = json as? [String: Any] else {
            return try Message2(json: json)
        }
        buildIndexes(dict)
        var message = try Message2(json: dict)
        resolveFields(&message, raw: dict)
        return message
    }

    private func buildIndexes(_ dict: [String: Any]) {
        if (dict["type"] as? String) == "assistant" {
            if let _idx0 = (dict["message"]) as? [String: Any] {
                if let _idxArr = (_idx0["content"]) as? [[String: Any]] {
                    for _item in _idxArr {
                        guard (_item["type"] as? String) == "tool_use" else { continue }
                        if let _k = _item["id"] as? String,
                           let _v = _item["name"] as? String {
                            resolvedToolIndex[_k] = _v
                        }
                    }
                }
            }
        }
        if (dict["type"] as? String) == "control_request" {
            if let _dp0 = (dict["request"]) as? [String: Any] {
                if let _k = (dict["request_id"] ?? dict["requestID"]) as? String,
                   let _v = (_dp0["tool_name"] ?? _dp0["toolName"]) as? String {
                    resolvedRequestIndex[_k] = _v
                }
            }
        }
    }

    private func resolveFields(_ message: inout Message2, raw: [String: Any]) {
        if case .user(var _parent) = message {
            if let _resultRaw = (raw["tool_use_result"] ?? raw["toolUseResult"]),
               _resultRaw is [String: Any] {
                if let _res0 = (raw["message"]) as? [String: Any] {
                    if let _resArr = (_res0["content"]) as? [[String: Any]] {
                        var _tag: String?
                        for _item in _resArr {
                            guard (_item["type"] as? String) == "tool_result" else { continue }
                            if let _lid = (_item["tool_use_id"] ?? _item["toolUseID"]) as? String {
                                _tag = resolvedToolIndex[_lid]
                                break
                            }
                        }
                        if let tag = _tag,
                           let resolved = try? ToolUseResult(json: _resultRaw, resolving: tag) {
                            _parent.toolUseResult = resolved
                            message = .user(_parent)
                        }
                    }
                }
            }
        }
    }
}

