4	// MARK: - Helpers
5	
6	private func camelToSnake(_ s: String) -> String {
7	    var result = ""
8	    let chars = Array(s)
9	    for (i, c) in chars.enumerated() {
10	        if c.isUppercase {
11	            if i > 0 && chars[i-1].isLowercase { result += "_" }
12	            else if i > 0 && i+1 < chars.count && chars[i-1].isUppercase && chars[i+1].isLowercase { result += "_" }
13	        }
14	        result += String(c).lowercased()
15	    }
16	    return result
17	}
18	
19	private func normalizeForComparison(_ json: Any) -> Any {
20	    if let dict = json as? [String: Any] {
21	        var result: [String: Any] = [:]
22	        for (key, value) in dict {
23	            if value is NSNull { continue }
24	            let snakeKey = key.hasPrefix("_") ? key : camelToSnake(key)
25	            result[snakeKey] = normalizeForComparison(value)
26	        }
27	        return result
28	    }
29	    if let arr = json as? [Any] {
30	        return arr.map { normalizeForComparison($0) }
31	    }
32	    return json
33	}
