35	// MARK: - DiffCollector
36	
37	private struct DiffCollector {
38	    var missingKeys: [String: Int] = [:]
39	    var extraKeys: [String: Int] = [:]
40	    var valueMismatches: [String: Int] = [:]
41	
42	    mutating func compare(original: Any, typed: Any, path: String) {
43	        if let origDict = original as? [String: Any],
44	           let typedDict = typed as? [String: Any] {
45	            for key in origDict.keys {
46	                let childPath = path.isEmpty ? key : "\(path).\(key)"
47	                if let typedVal = typedDict[key] {
48	                    compare(original: origDict[key]!, typed: typedVal, path: childPath)
49	                } else {
50	                    missingKeys[childPath, default: 0] += 1
51	                }
52	            }
53	            for key in typedDict.keys where origDict[key] == nil {
54	                extraKeys[(path.isEmpty ? key : "\(path).\(key)"), default: 0] += 1
55	            }
56	            return
57	        }
58	
59	        if let origArr = original as? [Any], let typedArr = typed as? [Any] {
60	            let childPath = "\(path)[]"
61	            for i in 0..<max(origArr.count, typedArr.count) {
62	                if i < origArr.count && i < typedArr.count {
63	                    compare(original: origArr[i], typed: typedArr[i], path: childPath)
64	                } else if i < origArr.count {
65	                    missingKeys["\(childPath)[overflow]", default: 0] += 1
66	                } else {
67	                    extraKeys["\(childPath)[overflow]", default: 0] += 1
68	                }
69	            }
70	            return
71	        }
72	
73	        if !(original as AnyObject).isEqual(typed as AnyObject) {
74	            valueMismatches[path, default: 0] += 1
75	        }
76	    }
77	}
78	
79	// MARK: - TypedJSONReport
80	
81	private struct TypedJSONReport {
82	    var parseErrors = 0
83	    var perVariant: [String: VariantStats] = [:]
84	    var globalDiffs = DiffCollector()
85	
86	    struct VariantStats {
87	        var total = 0
88	        var exactMatch = 0
89	        var diffs = DiffCollector()
90	    }
91	
92	    mutating func record(variant: String, original: Any, typed: Any) {
93	        let normOrig = normalizeForComparison(original)
94	        let normTyped = normalizeForComparison(typed)
95	
96	        var stats = perVariant[variant] ?? VariantStats()
97	        stats.total += 1
98	
99	        if (normOrig as AnyObject).isEqual(normTyped as AnyObject) {
100	            stats.exactMatch += 1
101	        } else {
102	            stats.diffs.compare(original: normOrig, typed: normTyped, path: "")
103	            globalDiffs.compare(original: normOrig, typed: normTyped, path: "")
104	        }
105	        perVariant[variant] = stats
106	    }
107	
108	    func write(to path: String) {
109	        var lines: [String] = []
110	        lines.append("=== Typed JSON E2E Summary ===")
111	        lines.append("Generated: \(ISO8601DateFormatter().string(from: Date()))")
112	        let total = perVariant.values.reduce(0) { $0 + $1.total }
113	        lines.append("Total records: \(total)")
114	        lines.append("Parse errors: \(parseErrors)")
115	        lines.append("")
116	
117	        lines.append("Per-variant breakdown:")
118	        for (name, stats) in perVariant.sorted(by: { $0.value.total > $1.value.total }) {
119	            let pct = stats.total > 0 ? Double(stats.exactMatch) / Double(stats.total) * 100 : 0
120	            let diff = stats.total - stats.exactMatch
121	            lines.append(String(format: "  %-25s %5d total  %5d exact (%5.1f%%)  %5d diff",
122	                                (name as NSString).utf8String!, stats.total, stats.exactMatch, pct, diff))
123	        }
124	        lines.append("")
125	
126	        lines.append("Top missing keys (original has, typed missing) — top 30:")
127	        let topMissing = globalDiffs.missingKeys.sorted { $0.value > $1.value }.prefix(30)
128	        for (path, count) in topMissing {
129	            lines.append("  \(path): \(count) occurrences")
130	        }
131	        lines.append("")
132	
133	        lines.append("Top value mismatches (same key, different value) — top 20:")
134	        let topMismatch = globalDiffs.valueMismatches.sorted { $0.value > $1.value }.prefix(20)
135	        for (path, count) in topMismatch {
136	            lines.append("  \(path): \(count) occurrences")
137	        }
138	
139	        if !globalDiffs.extraKeys.isEmpty {
140	            lines.append("")
141	            lines.append("Extra keys (typed has, original missing) — top 10:")
142	            let topExtra = globalDiffs.extraKeys.sorted { $0.value > $1.value }.prefix(10)
143	            for (path, count) in topExtra {
144	                lines.append("  \(path): \(count) occurrences")
145	            }
146	        }
147	
148	        try? lines.joined(separator: "\n").write(toFile: path, atomically: true, encoding: .utf8)
149	    }
150	}
