153	
154	private func loadAllJSONLRecords() -> [(file: String, line: Int, dict: [String: Any])] {
155	    let home = FileManager.default.homeDirectoryForCurrentUser
156	    let searchRoots = [
157	        home.appendingPathComponent(".claude/projects"),
158	        home.appendingPathComponent(".cache/ccterm/export"),
159	    ]
160	    var results: [(String, Int, [String: Any])] = []
161	    for root in searchRoots {
162	        guard let enumerator = FileManager.default.enumerator(
163	            at: root, includingPropertiesForKeys: nil
164	        ) else { continue }
165	        for case let fileURL as URL in enumerator {
166	            guard fileURL.pathExtension == "jsonl" else { continue }
167	            guard let data = try? Data(contentsOf: fileURL),
168	                  let content = String(data: data, encoding: .utf8) else { continue }
169	            for (i, line) in content.split(separator: "\n").enumerated() {
170	                guard let lineData = line.data(using: .utf8),
171	                      let json = try? JSONSerialization.jsonObject(with: lineData),
172	                      let dict = json as? [String: Any] else { continue }
173	                results.append((fileURL.path, i + 1, dict))
174	            }
175	        }
176	    }
177	    return results
178	}
