"""Shared utilities: config, data loading, key normalization, FK resolution."""

import json
import glob
import re
import sys
from collections import Counter
from pathlib import Path

SKILL_DIR = Path(__file__).parent
PROJECT_ROOT = SKILL_DIR.parent.parent.parent  # .claude/skills/schema-infer/ → project root
OUTPUT_DIR = PROJECT_ROOT / "schema-infer"
OUTPUT_DIR.mkdir(parents=True, exist_ok=True)
CONFIG_PATH = OUTPUT_DIR / "disc_config.json"
SCHEMA_PATH = OUTPUT_DIR / "schema.json"
ALT_NAMES_PATH = OUTPUT_DIR / "alt_names.json"
FK_RULES_PATH = SKILL_DIR / "fk_rules.json"
TOOL_RULES_PATH = OUTPUT_DIR / "tool_rules.json"
MIN_COVERAGE = 0.3
MAX_CARDINALITY_RATIO = 0.1

DATA_PATTERNS = [
    "~/.claude/projects/**/*.jsonl",
    "~/.cache/ccterm/export/*.jsonl",
]


def load_config() -> dict:
    if CONFIG_PATH.exists():
        with open(CONFIG_PATH) as f:
            return json.load(f)
    return {"confirmed": {}, "rejected": []}


def save_config(config: dict):
    with open(CONFIG_PATH, "w") as f:
        json.dump(config, f, indent=2)


# ---------------------------------------------------------------------------
# Key normalization: camelCase → snake_case
# ---------------------------------------------------------------------------

_camel_re1 = re.compile(r'([A-Z]+)([A-Z][a-z])')
_camel_re2 = re.compile(r'([a-z0-9])([A-Z])')

# Global registry: snake_name → set of original names seen
_alt_names: dict[str, set[str]] = {}


def _to_snake(key: str) -> str:
    """Convert a camelCase key to snake_case. Already snake_case keys pass through."""
    s = _camel_re1.sub(r'\1_\2', key)
    s = _camel_re2.sub(r'\1_\2', s)
    return s.lower()


def normalize_key(key: str) -> str:
    """Normalize a key to snake_case and track alt names."""
    if key.startswith("_"):
        return key
    snake = _to_snake(key)
    if snake != key:
        alt_set = _alt_names.setdefault(snake, set())
        alt_set.add(key)
    return snake


def normalize_obj(obj):
    """Recursively normalize all dict keys to snake_case."""
    if isinstance(obj, dict):
        return {normalize_key(k): normalize_obj(v) for k, v in obj.items()}
    elif isinstance(obj, list):
        return [normalize_obj(item) for item in obj]
    return obj


def get_alt_names() -> dict[str, list[str]]:
    """Return alt names map: snake_name → list of original camelCase names."""
    return {k: sorted(v) for k, v in _alt_names.items() if v}


def save_alt_names():
    """Persist alt names to disk."""
    with open(ALT_NAMES_PATH, "w") as f:
        json.dump(get_alt_names(), f, indent=2)


def load_alt_names() -> dict[str, list[str]]:
    """Load persisted alt names."""
    if ALT_NAMES_PATH.exists():
        with open(ALT_NAMES_PATH) as f:
            return json.load(f)
    return {}


# ---------------------------------------------------------------------------
# Foreign key resolution (declarative, driven by fk_rules.json)
# ---------------------------------------------------------------------------

def load_fk_rules() -> list[dict]:
    if FK_RULES_PATH.exists():
        with open(FK_RULES_PATH) as f:
            return json.load(f)
    return []


def load_tool_rules() -> list[dict]:
    if TOOL_RULES_PATH.exists():
        with open(TOOL_RULES_PATH) as f:
            return json.load(f)
    return []


def save_tool_rules(rules: list[dict]):
    with open(TOOL_RULES_PATH, "w") as f:
        json.dump(rules, f, indent=2)
        f.write("\n")


def _get_nested(obj, path: str):
    """Resolve a dotted path like 'request.tool_name' on a dict."""
    for part in path.split('.'):
        if not isinstance(obj, dict):
            return None
        obj = obj.get(part)
    return obj


def _match_record(rec: dict, match: dict) -> bool:
    """Check if record satisfies all match conditions."""
    for key, val in match.items():
        if val == "$exists":
            if key not in rec:
                return False
        else:
            if rec.get(key) != val:
                return False
    return True


def _resolve_foreign_keys(file_records: list[dict], rules: list[dict]):
    """Apply FK resolution rules within a session file."""
    for rule in rules:
        name = rule["name"]
        idx_cfg = rule["index"]
        res_cfg = rule["resolve"]

        # Build index: key → value
        index: dict[str, str] = {}
        for rec in file_records:
            if not _match_record(rec, idx_cfg.get("match", {})):
                continue
            if "iterate" in idx_cfg:
                items = _get_nested(rec, idx_cfg["iterate"])
                if not isinstance(items, list):
                    continue
                sources = [item for item in items if isinstance(item, dict)]
                if "filter" in idx_cfg:
                    sources = [s for s in sources if _match_record(s, idx_cfg["filter"])]
            else:
                sources = [rec]
            for src in sources:
                k = _get_nested(src, idx_cfg["key"])
                v = _get_nested(src, idx_cfg["value"])
                if k is not None and v is not None:
                    index[k] = v

        if not index:
            continue

        # Resolve: lookup in index, inject into target
        for rec in file_records:
            if not _match_record(rec, res_cfg.get("match", {})):
                continue
            lookup_val = None
            if "iterate" in res_cfg:
                items = _get_nested(rec, res_cfg["iterate"])
                if not isinstance(items, list):
                    continue
                for item in items:
                    if not isinstance(item, dict):
                        continue
