// MARK: Test 4 — Direct resolving init

func testDirectResolving() throws {
    let bashJson: [String: Any] = [
        "stdout": "hello world",
        "stderr": "",
        "interrupted": false,
        "is_image": false,
    ]
    let result = try ToolUseResultObject(json: bashJson, resolving: "Bash")
    if case .Bash(let bash) = result {
        XCTAssertEqual(bash.stdout, "hello world")
        XCTAssertEqual(bash.stderr, "")
    } else {
        XCTFail("Expected .Bash, got \(result)")
    }

    // Fallback init should produce .unknown
    let fallback = try ToolUseResultObject(json: bashJson)
    if case .unknown(let name, _) = fallback {
        XCTAssertEqual(name, "unresolved")
    } else {
        XCTFail("Expected .unknown(unresolved), got \(fallback)")
    }

    // Unknown tool name
    let unknown = try ToolUseResultObject(json: bashJson, resolving: "NonExistentTool")
    if case .unknown(let name, _) = unknown {
        XCTAssertEqual(name, "NonExistentTool")
    } else {
        XCTFail("Expected .unknown(NonExistentTool), got \(unknown)")
    }
}

// MARK: Test 5 — ToolUseResult resolving propagation

func testToolUseResultResolvingPropagation() throws {
    let editJson: [String: Any] = [
        "file_path": "/tmp/test.swift",
        "old_string": "foo",
        "new_string": "bar",
        "original_file": "original content",
        "replace_all": false,
        "user_modified": false,
    ]
    let result = try ToolUseResult(json: editJson, resolving: "Edit")
    if case .object(let obj) = result {
        if case .Edit(let edit) = obj {
            XCTAssertEqual(edit.filePath, "/tmp/test.swift")
        } else {
            XCTFail("Expected .Edit, got \(obj)")
        }
    } else {
        XCTFail("Expected .object, got \(result)")
    }

    // String result should pass through unchanged
    let stringResult = try ToolUseResult(json: "some string" as Any, resolving: "Bash")
    if case .string(let s) = stringResult {
        XCTAssertEqual(s, "some string")
    } else {
        XCTFail("Expected .string, got \(stringResult)")
    }
}

