    func testIsUnresolved() throws {
        let json: [String: Any] = ["stdout": "x", "stderr": "", "interrupted": false, "is_image": false]
        let toolUseJson: [String: Any] = ["type": "tool_use", "id": "t1", "name": "Bash", "input": ["command": "x"]]
