            do {
                let msg = try Message2(json: dict)
                let typed = msg.toTypedJSON()
                let variant = dict["type"] as? String ?? dict["subtype"] as? String ?? "unknown"
                report.record(variant: variant, original: dict, typed: typed)
            } catch {
                report.parseErrors += 1
