import Foundation

extension Message2AssistantMessage {
    public init(json: Any) throws {
        let r = try JSONReader(json, context: "Message2AssistantMessage")
        self._raw = r.dict
        self.container = r.raw("container")
        self.content = try r.decodeArray("content")
        self.contextManagement = r.decodeIfPresent("context_management")
        self.id = try r.need("id")
        self.model = try r.need("model")
        self.role = try r.need("role")
        self.stopReason = try r.need("stop_reason")
        self.stopSequence = try r.need("stop_sequence")
        self.`type` = try r.need("type")
        self.usage = try r.decode("usage")
    }

    public func toJSON() -> Any { _raw }
}

extension Message2AssistantMessage {
    public func toTypedJSON() -> Any {
        var d: [String: Any] = [:]
        if let v = container { d["container"] = v }
        d["content"] = content.map { $0.toTypedJSON() }
        if let v = contextManagement { d["context_management"] = v.toTypedJSON() }
        d["id"] = id
        d["model"] = model
        d["role"] = role
        if let v = stopReason { d["stop_reason"] = v }
        if let v = stopSequence { d["stop_sequence"] = v }
        d["type"] = `type`
        d["usage"] = usage.toTypedJSON()
        return d
    }
}

