import Foundation

extension MessageUsage {
    public init(json: Any) throws {
        let r = try JSONReader(json, context: "MessageUsage")
        self._raw = r.dict
        self.cacheCreation = try r.decode("cache_creation")
        self.cacheCreationInputTokens = try r.needInt("cache_creation_input_tokens", alt: "cacheCreationInputTokens")
        self.cacheReadInputTokens = try r.needInt("cache_read_input_tokens", alt: "cacheReadInputTokens")
        self.inferenceGeo = r.string("inference_geo")
        self.inputTokens = try r.needInt("input_tokens", alt: "inputTokens")
        self.iterations = r.rawArray("iterations")
        self.outputTokens = try r.needInt("output_tokens", alt: "outputTokens")
        self.serverToolUse = r.decodeIfPresent("server_tool_use")
        self.serviceTier = try r.need("service_tier")
        self.speed = r.string("speed")
    }

    public func toJSON() -> Any { _raw }
}

extension MessageUsage {
    public func toTypedJSON() -> Any {
        var d: [String: Any] = [:]
        d["cache_creation"] = cacheCreation.toTypedJSON()
        d["cache_creation_input_tokens"] = cacheCreationInputTokens
        d["cache_read_input_tokens"] = cacheReadInputTokens
        if let v = inferenceGeo { d["inference_geo"] = v }
        d["input_tokens"] = inputTokens
        if let v = iterations { d["iterations"] = v }
        d["output_tokens"] = outputTokens
        if let v = serverToolUse { d["server_tool_use"] = v.toTypedJSON() }
        if let v = serviceTier { d["service_tier"] = v }
        if let v = speed { d["speed"] = v }
        return d
    }
}

